151	  let entries=Object.entries(goals).sort((a,b)=>b[1].created_at-a[1].created_at),grid=document.getElementById('goalsGrid');
152	  if(!entries.length){grid.innerHTML='<div class="glass empty-state"><div class="empty-icon">🎯</div><p>No active goals. Submit a goal above to get started.</p></div>';return}
153	  document.getElementById('activeCount').textContent=entries.filter(([,g])=>g.status==='active').length;
