// ── Error Recovery State ───────────────────────────────────
let recoveryState = {
  active: false,
  sessionId: null,
  goalId: null,
  stepCount: 0,
  subGoal: '',
  goal: '',
  pageUrl: '',
  pausedAt: null,
  pauseReason: '',
  pageType: '',
  pausedTimer: null
};

// ── DOM refs (cached after first open) ─────────────────────
let liveDOM = {};

function cacheLiveDOM() {
  liveDOM.overlay    = document.getElementById('liveOverlay');
  liveDOM.panel      = liveDOM.overlay.querySelector('.live-panel');
  liveDOM.banner     = document.getElementById('pauseBanner');
  liveDOM.pauseText  = document.getElementById('pauseText');
  liveDOM.pauseReason= document.getElementById('pauseReason');
  liveDOM.viewport   = document.getElementById('screenshotViewport');
  liveDOM.screenshot = document.getElementById('liveScreenshot');
  liveDOM.rippleLayer= document.getElementById('rippleLayer');
  liveDOM.textInput  = document.getElementById('textInput');
  liveDOM.resumeBtn  = document.getElementById('resumeBtn');
  liveDOM.cancelBtn  = document.getElementById('cancelBtn');
  liveDOM.sessGoal   = document.getElementById('sessGoal');
  liveDOM.sessSubGoal= document.getElementById('sessSubGoal');
  liveDOM.sessSteps  = document.getElementById('sessSteps');
  liveDOM.sessPaused = document.getElementById('sessPaused');
  liveDOM.sessUrl    = document.getElementById('sessUrl');
}

// ── Open the overlay ───────────────────────────────────────
function openRecoveryPanel(data) {
  if (!liveDOM.overlay) cacheLiveDOM();

  recoveryState.active    = true;
  recoveryState.sessionId = data.session_id;
  recoveryState.goalId    = data.goal_id;
  recoveryState.pageType  = data.page_type;
  recoveryState.pauseReason = data.reason;
  recoveryState.stepCount = data.step_count || 0;
  recoveryState.subGoal   = data.sub_goal || '';
  recoveryState.goal      = data.goal_description || '';
  recoveryState.pageUrl   = data.page_url || '';
  recoveryState.pausedAt  = new Date(data.paused_at || Date.now());

  // Banner
  liveDOM.banner.className = 'pause-banner';
  liveDOM.pauseText.textContent = 'AGENT PAUSED';
  liveDOM.pauseReason.textContent = data.reason || 'Escalation';

  // Color variant for login/paywall (non-critical, warning tone)
  if (['login_wall', 'paywall'].includes(data.page_type)) {
    liveDOM.banner.classList.add('warning');
  }

  // Session card
  liveDOM.sessGoal.textContent    = recoveryState.goal;
  liveDOM.sessSubGoal.textContent = recoveryState.subGoal;
  liveDOM.sessSteps.textContent   = String(recoveryState.stepCount);
  liveDOM.sessUrl.textContent     = recoveryState.pageUrl;
  updatePausedTimer();

  // Clear prior state
  liveDOM.screenshot.src = '';
  liveDOM.textInput.value = '';
  liveDOM.rippleLayer.innerHTML = '';

  // Show
  liveDOM.overlay.classList.remove('hidden');
  liveDOM.resumeBtn.classList.add('pulse-glow');

  // Start elapsed timer
  if (recoveryState.pausedTimer) clearInterval(recoveryState.pausedTimer);
  recoveryState.pausedTimer = setInterval(updatePausedTimer, 1000);

  // Focus text input
  setTimeout(() => liveDOM.textInput.focus(), 100);
}

function updatePausedTimer() {
  if (!recoveryState.pausedAt || !liveDOM.sessPaused) return;
  let elapsed = Math.floor((Date.now() - recoveryState.pausedAt) / 1000);
  let m = Math.floor(elapsed / 60);
  let s = elapsed % 60;
  liveDOM.sessPaused.textContent = m + 'm ' + String(s).padStart(2,'0') + 's';
}

// ── Close the overlay ──────────────────────────────────────
function closeRecoveryPanel() {
  recoveryState.active = false;
  if (recoveryState.pausedTimer) {
    clearInterval(recoveryState.pausedTimer);
    recoveryState.pausedTimer = null;
  }
  if (liveDOM.overlay) liveDOM.overlay.classList.add('hidden');

  // Notify server we are cancelling (only if the goal was not resumed)
  if (ws && wsConnected && recoveryState.sessionId) {
    ws.send(JSON.stringify({
      type: 'cancel_recovery',
      session_id: recoveryState.sessionId
    }));
  }
}

// ── Screenshot frame handler ───────────────────────────────
function updateScreenshotFrame(data) {
  if (!recoveryState.active) return;
  if (data.session_id !== recoveryState.sessionId) return;

  // Only update if user is not currently interacting with old frame
  // (if we update mid-hover it jumps — debounce by checking no
  //  mousedown is active)
  if (!liveDOM.viewport || liveDOM.viewport.dataset.pressed === '1') return;

  liveDOM.screenshot.src = 'data:image/png;base64,' + data.data_base64;
}

// ── Click handling on the screenshot ───────────────────────
if (liveDOM.viewport) { /* placeholder — wired on first open */ }

function wireScreenshotEvents() {
  let vp = liveDOM.viewport;

  // Track pressed state so we don't swap frames mid-interaction
  vp.addEventListener('pointerdown', (e) => {
    vp.dataset.pressed = '1';
  });

  vp.addEventListener('pointerup', (e) => {
    vp.dataset.pressed = '0';

    let rect = vp.getBoundingClientRect();
    let img = liveDOM.screenshot;
    let imgRect = img.getBoundingClientRect();

    // Compute click position relative to the image, NOT the viewport
    let x = e.clientX - imgRect.left;
    let y = e.clientY - imgRect.top;

    // Scale to actual page coordinates
    let scaleX = img.naturalWidth  / imgRect.width;
    let scaleY = img.naturalHeight / imgRect.height;
    let pageX = Math.round(x * scaleX);
    let pageY = Math.round(y * scaleY);

    // Ripple at click position (relative to viewport)
    spawnRipple(e.clientX - rect.left, e.clientY - rect.top);

    // Send to server
    if (ws && wsConnected) {
      ws.send(JSON.stringify({
        type: 'user_click',
        session_id: recoveryState.sessionId,
        x: pageX,
        y: pageY
      }));
    }
  });

  // Prevent text selection during clicks
  vp.addEventListener('selectstart', (e) => { e.preventDefault(); });
}

function spawnRipple(x, y) {
  let el = document.createElement('div');
  el.className = 'click-ripple';
  el.style.left = x + 'px';
  el.style.top  = y + 'px';
  liveDOM.rippleLayer.appendChild(el);
  el.addEventListener('animationend', () => el.remove());
}

// ── Text input ─────────────────────────────────────────────
function wireTextInput() {
  let inp = liveDOM.textInput;

  // Send typed character immediately (keypress for printable chars)
  inp.addEventListener('input', () => {
    // We don't send on every input — user presses Enter to commit
  });

  inp.addEventListener('keydown', (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      // Send typed text
      let text = inp.value.trim();
      if (text && ws && wsConnected) {
        ws.send(JSON.stringify({
          type: 'user_type',
          session_id: recoveryState.sessionId,
          text: text
        }));
      }
      // Also send Enter key
      if (ws && wsConnected) {
        ws.send(JSON.stringify({
          type: 'user_key',
          session_id: recoveryState.sessionId,
          key: 'Enter'
        }));
      }
      inp.value = '';
    } else if (e.key === 'Escape') {
      inp.value = '';
    }
  });
}

// ── Key buttons in action bar ──────────────────────────────
function wireKeyButtons() {
  let keys = {
    keyTab:       'Tab',
    keyEnter:     'Enter',
    keyEscape:    'Escape',
    keyBackspace: 'Backspace'
  };
  for (let [id, key] of Object.entries(keys)) {
    let btn = document.getElementById(id);
    if (btn) {
      btn.addEventListener('click', () => {
        if (ws && wsConnected) {
          ws.send(JSON.stringify({
            type: 'user_key',
            session_id: recoveryState.sessionId,
            key: key
          }));
        }
      });
    }
  }
}

// ── Resume / Cancel buttons ────────────────────────────────
function wireActionButtons() {
  liveDOM.resumeBtn.addEventListener('click', () => {
    if (ws && wsConnected) {
      ws.send(JSON.stringify({
        type: 'resume_agent',
        session_id: recoveryState.sessionId
      }));
      // Optimistically close — the agent_resumed event will confirm
      closeRecoveryPanel();
    }
  });

  liveDOM.cancelBtn.addEventListener('click', () => {
    if (confirm('Cancel this goal? The agent will stop and the goal will be marked as failed.')) {
      if (ws && wsConnected) {
        ws.send(JSON.stringify({
          type: 'cancel_goal',
          session_id: recoveryState.sessionId,
          goal_id: recoveryState.goalId
        }));
      }
      closeRecoveryPanel();
    }
  });

  // Keyboard shortcut: 'r' or 'R' to resume
  document.addEventListener('keydown', (e) => {
    if (!recoveryState.active) return;

    // Don't fire shortcuts when typing in the input
    if (document.activeElement === liveDOM.textInput) return;

    switch (e.key) {
      case 'r':
      case 'R':
        e.preventDefault();
        liveDOM.resumeBtn.click();
        break;
      case 'Escape':
        e.preventDefault();
        liveDOM.cancelBtn.click();
        break;
    }
  });
}

// ── Wire all interaction handlers on first open ─────────────
let handlersWired = false;
function ensureHandlersWired() {
  if (handlersWired) return;
  cacheLiveDOM();
  wireScreenshotEvents();
  wireTextInput();
  wireKeyButtons();
  wireActionButtons();
  handlersWired = true;
}

// ── Extend existing handleEvent() ──────────────────────────
// Add these cases to the existing handleEvent(d) function:

const ORIGINAL_handleEvent = handleEvent;
handleEvent = function(d) {
  // New event types for error recovery
  if (d.type === 'agent_paused') {
    ensureHandlersWired();
    openRecoveryPanel(d);
    return;
  }
  if (d.type === 'screenshot_frame') {
    updateScreenshotFrame(d);
    return;
  }
  if (d.type === 'agent_resumed') {
    closeRecoveryPanel();
    showToast('Agent resumed — continuing goal execution', 'success');
    return;
  }

  // Fall through to original handler
  ORIGINAL_handleEvent(d);
};
